import { useState } from 'react';
import toast from 'react-hot-toast';
import API from '../../utils/api';

export default function QRScanner() {
  const [uucms, setUucms] = useState('');
  const [eventId, setEventId] = useState('');
  const [events, setEvents] = useState([]);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  useState(() => {
    API.get('/events').then(r => setEvents(r.data));
  }, []);

  const handleCheckin = async () => {
    if (!uucms || !eventId) return toast.error('Enter UUCMS number and select event');
    setLoading(true);
    try {
      const res = await API.post('/registrations/checkin', { uucms, eventId });
      setResult(res.data);
      toast.success(res.data.message);
      setUucms('');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Check-in failed');
      setResult(null);
    } finally { setLoading(false); }
  };

  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-6">QR Check-In Scanner</h1>

      <div className="max-w-lg">
        <div className="card mb-4">
          <div className="text-center text-5xl mb-4">📷</div>
          <p className="text-sm text-gray-500 text-center mb-6">
            Scan player QR code or manually enter UUCMS number to check in
          </p>

          <div className="space-y-3">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Event</label>
              <select className="input-field" value={eventId} onChange={e => setEventId(e.target.value)}>
                <option value="">Select Event</option>
                {events.map(ev => <option key={ev._id} value={ev._id}>{ev.title}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">UUCMS Number</label>
              <input
                className="input-field text-lg font-mono"
                placeholder="U02CG23S0001"
                value={uucms}
                onChange={e => setUucms(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleCheckin()}
                autoFocus
              />
              <p className="text-xs text-gray-400 mt-1">Press Enter or click Check In</p>
            </div>
            <button onClick={handleCheckin} disabled={loading} className="btn-primary w-full py-3 rounded-xl font-semibold">
              {loading ? 'Checking in...' : '✅ Check In Player'}
            </button>
          </div>
        </div>

        {result && (
          <div className="card bg-green-50 border-green-200">
            <div className="text-center">
              <div className="text-4xl mb-2">✅</div>
              <h3 className="font-bold text-green-900 text-lg">{result.player?.name}</h3>
              <p className="text-green-700 text-sm">{result.player?.uucms} • {result.player?.department}</p>
              <p className="text-green-600 font-semibold mt-2">{result.message}</p>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
